            const saveChatToDb = async (chat) => {
                try {
                    await fetch(`${API_URL}/api/save-chat`, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify(chat)
                    });
                } catch (err) {
                    console.error('Failed to save chat to DB:', err);
                }
            };
            
            // Delete chat from database
