                        const base64 = ev.target.result.split(',')[1];
                        // Try to extract text for non-binary files
                        const textReader = new FileReader();
                        textReader.onload = (ev2) => {
                            const text = ev2.target.result;
                            const isText = !text.includes('\0');
                            setCatalystUploadedFiles(prev => [...prev, {
                                name: file.name, type: file.type, data: base64,
                                text: isText ? text.slice(0, 50000) : '',
                            }]);
                        };
                        textReader.readAsText(file);
